(()=>{window.JM_RECOLOR_DATA=Object.assign(window.JM_RECOLOR_DATA||{},{"ponytail/hair/purple":"","ponytail/hair/red":"","ponytail/hair/silver":"","ponytail/hair/teal":"","ponytail/jacket/academy":"","ponytail/jacket/explorer":"","ponytail/jacket/haori":"","ponytail/pants/black":""});window.getJapaneseMinerRecolor=window.getJapaneseMinerRecolor||((hair,part,id)=>{const value=window.JM_RECOLOR_DATA[hair+'/'+part+'/'+id];return value?'url("data:image/webp;base64,'+value+'")':'none';});})();
